// Source: https://github.com/sivolko/kql-library
// Collected: 2026-05-11
// KQL Library - https://github.com/sivolko/kql-library

let dt_lookBack = 1h;
let ioc_lookBack = 14d;
let UrlClickEvents_ = materialize(UrlClickEvents
    | where TimeGenerated >= ago(dt_lookBack)
    | extend UrlClickEvents_TimeGenerated = TimeGenerated);
let ChainReportID = UrlClickEvents_
    | mv-expand todynamic(UrlChain)
    | extend UrlChain = tolower(UrlChain)
    | project ReportId, Url, UrlChain;
// Url is not always in UrlChain, so we need to check both
let ClickedUrls = 
  (union isfuzzy=false (ChainReportID), (ChainReportID | project Url = UrlChain))
  | distinct Url
  | summarize make_list(Url);
let TI = materialize(ThreatIntelligenceIndicator
  | where TimeGenerated >= ago(ioc_lookBack)
  | where isnotempty(Url) and tolower(Url) in (ClickedUrls)
  | summarize LatestIndicatorTime = arg_max(TimeGenerated, *) by IndicatorId
  | where Active == true and ExpirationDateTime > now()
  | project-rename TI_Url = Url, TI_Type = Type
  );
(union isfuzzy=false (TI | join kind=innerunique (ChainReportID) on $left.TI_Url == $right.UrlChain),
  (TI | join kind=innerunique (ChainReportID) on $left.TI_Url == $right.Url))
| project-away UrlChain
| join kind=innerunique (UrlClickEvents_) on ReportId
| where UrlClickEvents_TimeGenerated < ExpirationDateTime
| summarize UrlClickEvents_TimeGenerated = arg_max(UrlClickEvents_TimeGenerated, *) by IndicatorId
| project UrlClickEvents_TimeGenerated, AccountUpn, Description, ActivityGroupNames, IndicatorId, ThreatType, ExpirationDateTime, ConfidenceScore, Url, NetworkMessageId
| extend timestamp = UrlClickEvents_TimeGenerated
| extend timestamp = UrlClickEvents_TimeGenerated, Name = tostring(split(AccountUpn, '@', 0)[0]), UPNSuffix = tostring(split(AccountUpn, '@', 1)[0])

// Source: https://github.com/sivolko/kql-library
// Collected: 2026-05-11
// KQL Library - https://github.com/sivolko/kql-library

let lookback = 1h;
let port_count_threshold = 160;
let minConfidenceScore = 50;
let ignoredactivity = dynamic(["deny","drop"]);
let gpip = _GetWatchlist("gpgateway") | project GPGatewayIP;
let siteip = _GetWatchlist("sitepubip") | project SitePublicIP;
let dastip = _GetWatchlist("dastips") | project DastIP;
let qualys_ips = _GetWatchlist("qualysips") | project QualysIP;
let qualys_ranges = toscalar(_GetWatchlist("qualysips") | summarize make_set(QualysCIDR));
let PortScanningIPs = CommonSecurityLog
| where TimeGenerated > ago(lookback)
| where DeviceVendor contains "Palo"
| where Activity =~ 'TRAFFIC'
| where isnotempty(DestinationPort) and isnotempty(SourceIP)
| where not(ipv4_is_private(SourceIP))
| where SourceIP !in (gpip)
| where SourceIP !in (siteip)
| where SourceIP !in (qualys_ips)
| where SourceIP !in (dastip)
| where not(ipv4_is_in_any_range(SourceIP, qualys_ranges))
| where not(DeviceAction has_any (ignoredactivity))
| summarize PortSet = make_set(DestinationPort) by SourceIP, bin(TimeGenerated, 15m)
| where array_length(PortSet) > port_count_threshold
| extend PortCount = array_length(PortSet);
PortScanningIPs
| join kind=leftouter (
    ThreatIntelligenceIndicator
    | where TimeGenerated > ago(14d)
    | where ConfidenceScore >= minConfidenceScore
    | project ThreatIP = NetworkIP, ThreatType, Description, ConfidenceScore
) on $left.SourceIP == $right.ThreatIP
| extend ThreatMatch = iff(isnotempty(ThreatType), "Yes", "No")
| order by ThreatMatch desc, ConfidenceScore desc, PortCount desc

// Source: https://github.com/sivolko/kql-library
// Collected: 2026-05-11
// KQL Library - https://github.com/sivolko/kql-library

let timeframe = 7d;
let TI = ThreatIntelligenceIndicator
| where TimeGenerated > ago(timeframe)
| where Active == true and ExpirationDateTime > now();
CommonSecurityLog
| where TimeGenerated > ago(timeframe)
| join kind=inner (
    TI
) on $left.DestinationIP == $right.NetworkIP

// Source: https://github.com/sivolko/kql-library
// Collected: 2026-05-11
// KQL Library - https://github.com/sivolko/kql-library

let TI_Bag = ThreatIntelligenceIndicator | where isnotempty(NetworkSourceIP) | project NetworkSourceIP;

// Source: https://github.com/sivolko/kql-library
// Collected: 2026-05-11
// KQL Library - https://github.com/sivolko/kql-library

let dt_lookBack = 1h;
let Domains = ThreatIntelligenceIndicator
| where ExpirationDateTime > now()
| where Active == true
| where isnotempty(DomainName)
| project DomainName;
let DNE = DeviceNetworkEvents
    | extend Table = "DeviceNetworkEvents"
    | where TimeGenerated >= ago(dt_lookBack)
    | where isnotempty(RemoteUrl)
    | where RemoteUrl has_any (Domains)
    | project Table, TimeGenerated, InitiatingProcessAccountUpn, DeviceName, LocalIP, RemoteIP, RemoteUrl;
let Umbrella = Cisco_Umbrella
    | extend Table = "CiscoUmbrella"
    | where TimeGenerated >= ago(dt_lookBack)
    | extend TrimmedDNS = trim(@"[^\w]+",DnsQueryName)
    | extend User = parse_json(Identities)[1]
    | extend Device = parse_json(Identities)[0]
    | where TrimmedDNS has_any (Domains)
    | project Table, TimeGenerated, TrimmedDNS, User, Device;
union DNE, Umbrella

// Set to Hour Lookback and 14 Days Info

// Source: https://github.com/sivolko/kql-library
// Collected: 2026-05-11
// KQL Library - https://github.com/sivolko/kql-library

let dugganusa_iocs = ThreatIntelligenceIndicator
    | where SourceSystem == "DugganUSA-STIX-Feed"
    | where Active == true
    | summarize by NetworkIP, DomainName, FileHashValue;

// Match against CommonSecurityLog (firewall/proxy)
CommonSecurityLog
| where TimeGenerated > ago(24h)
| where DestinationIP in (dugganusa_iocs) or RequestURL has_any (dugganusa_iocs)
| project TimeGenerated, DeviceVendor, DeviceProduct, SourceIP, DestinationIP, RequestURL, Activity
| extend ThreatMatch = "DugganUSA IOC Match"

// Source: https://github.com/sivolko/kql-library
// Collected: 2026-05-11
// KQL Library - https://github.com/sivolko/kql-library

let Lookback = ago(7d);
// Get the OfficeActivity events and filter by OperationName
let OfficeEvents = OfficeActivity
| where TimeGenerated > Lookback
| where Operation in ("FileDownloaded", "FileUploaded")
| extend Domain = tostring(split(SourceRelativeUrl, "/")[2]) // extract the domain name from the file URL
| project TimeGenerated, UserId, Operation, SourceFileName, Domain;
// Get the ThreatIntelligenceIndicator records and filter by ThreatType
let TIRecords = ThreatIntelligenceIndicator
| where TimeGenerated > Lookback
| where ThreatType == "DomainName"
| project Domain = NetworkDestinationAsn, ThreatSeverity;
// Join the OfficeEvents and TIRecords tables on Domain
let JoinedEvents = OfficeEvents
| join kind=leftouter (
    TIRecords
) on Domain;
// Calculate the rarity score of each domain based on its frequency and threat level
// The rarity score is defined as log10(Count) * (ThreatLevel + 1), where Count is the number of events for each domain and ThreatLevel is a numeric value from 0 to 3
// The higher the rarity score, the more rare and potentially malicious the domain is
let RarityScore = JoinedEvents
| summarize Count = count() by Domain, ThreatSeverity // count the number of events for each domain and threat level combination
| extend RarityScore = log10(Count) * (ThreatSeverity + 1) // calculate the rarity score
| order by RarityScore desc; // order by rarity score in descending order
// Display the results
RarityScore

// Source: https://github.com/ugurkocde/kql_search_submissions
// Collected: 2026-05-11
// KQL Library - https://github.com/sivolko/kql-library

Syslog
| where SyslogMessage has_any ("chmod", "chown", "sudo -i", "su", "adduser", "passwd", "deluser")
| extend User = extract("USER=([^ ]+)", 1, SyslogMessage)
| extend CommandLine = extract("COMMAND=([^ ]+)", 1, SyslogMessage)
| summarize EventCount = count() by Computer, User, CommandLine

// Source: https://github.com/robert-iw3/rnd_proto
// Collected: 2026-05-11
// KQL Library - https://github.com/sivolko/kql-library

let internal_domains = dynamic(["contoso.com", "contoso.org"]);
// Add keywords that are common in your environment but might be flagged as suspicious.
let keyword_allowlist = dynamic([]);
// Add any legitimate external forwarding domains (e.g., for ticketing or CRM systems).
let external_forwarding_allowlist = dynamic([]);
// --- End Tuning Section ---

// Define suspicious keywords often used by attackers to find and hide sensitive emails.
let suspicious_keywords = dynamic(["invoice", "payment", "password", "phish", "hack", "warning", "security", "support", "undeliverable", "bank", "credential"]);
// Define folders that attackers might use to hide emails from the user.
let suspicious_folders = dynamic(["RSS Feeds", "Junk E-mail", "Conversation History", "Archive", "Deleted Items"]);

OfficeActivity
| where RecordType == "Exchange" and Operation in ("New-InboxRule", "Set-InboxRule")
// Unpack the parameters column into individual columns for easier analysis.
| evaluate bag_unpack(Parameters, "p_")
| extend
    RuleName = tostring(p_Name),
    DeleteMessage = tostring(p_DeleteMessage) == "True",
    MoveToFolder = tostring(p_MoveToFolder),
    ForwardTo = tostring(p_ForwardTo),
    ForwardAsAttachmentTo = tostring(p_ForwardAsAttachmentTo),
    RedirectTo = tostring(p_RedirectTo),
    SubjectOrBodyContainsWords = tostring(p_SubjectOrBodyContainsWords),
    SubjectContainsWords = tostring(p_SubjectContainsWords),
    BodyContainsWords = tostring(p_BodyContainsWords)
// Combine all forwarding/redirect fields and keyword fields for easier checking.
| extend AllForwardingRecipients = tolower(strcat(ForwardTo, ForwardAsAttachmentTo, RedirectTo))
| extend AllKeywords = tolower(strcat(SubjectOrBodyContainsWords, SubjectContainsWords, BodyContainsWords))
// Identify suspicious conditions based on the rule's actions.
| extend
    IsDeleting = DeleteMessage,
    IsMovingToSuspiciousFolder = MoveToFolder has_any (suspicious_folders),
    HasSuspiciousKeywords = AllKeywords has_any (suspicious_keywords) and AllKeywords !has_any (keyword_allowlist),
    IsExternalForwarding = isnotempty(AllForwardingRecipients) and
                           AllForwardingRecipients !has_any (internal_domains) and
                           AllForwardingRecipients !has_any (external_forwarding_allowlist)
// The core detection logic: alert if the rule deletes, moves to a suspicious folder, forwards externally, or uses suspicious keywords.
| where IsDeleting or IsMovingToSuspiciousFolder or IsExternalForwarding or HasSuspiciousKeywords
// Create a summary of why the rule is suspicious for the analyst.
| extend SuspiciousReason = strcat_array(
    dynamic([
        iff(IsDeleting, "Deletes messages", ""),
        iff(IsMovingToSuspiciousFolder, strcat("Moves to suspicious folder (", MoveToFolder, ")"), ""),
        iff(IsExternalForwarding, strcat("Forwards externally (", AllForwardingRecipients, ")"), ""),
        iff(HasSuspiciousKeywords, "Contains suspicious keywords", "")
    ]),
    ", "
)
| project
    TimeGenerated,
    User = UserId,
    SourceIp = ClientIPAddress,
    UserAgent = OfficeUserAgent,
    Operation,
    RuleName,
    SuspiciousReason,
    Parameters

// Source: https://github.com/DGovEnterprise/wasoc-notebook
// Collected: 2026-05-11
// KQL Library - https://github.com/sivolko/kql-library

OfficeActivity
| where Operation in ("FileSyncDownloadedFull", "FileDownloaded")
| where UserId contains "#ext#"
| summarize Count=count() by FileUrl = OfficeObjectId
| sort by Count desc

// Source: https://github.com/davidalonsod/Dalonso-Security-Repo
// Collected: 2026-05-11
// KQL Library - https://github.com/sivolko/kql-library

let _AuxiliaryTables = dynamic([
    "OfficeActivity", "AzureActivity", "Heartbeat",
    "SentinelHealth", "SecurityAlert", "SecurityIncident", "Operation"
]);
let _Top10 = 
    Usage
    | where TimeGenerated > ago(30d)
    | where IsBillable == true
    | where DataType !in (_AuxiliaryTables)
    | summarize TotalMB = sum(Quantity) by DataType
    | top 10 by TotalMB desc
    | project DataType;
Usage
| where TimeGenerated > ago(30d)
| where IsBillable == true
| where DataType in (_Top10)
| summarize DailyGB = round(sum(Quantity) / 1024.0, 3) by Day = bin(TimeGenerated, 1d), DataType
| order by Day asc, DailyGB desc

// Source: https://github.com/AndrewAltimit/exploits
// Collected: 2026-05-11
// KQL Library - https://github.com/sivolko/kql-library

let CopilotWindow = 60s;
let FileAccessThreshold = 10;  // flag if > 10 files accessed in window

let CopilotSummarizationEvents =
    OfficeActivity
    | where TimeGenerated > ago(7d)
    | where RecordType == "Copilot"
    | where Operation in ("CopilotEmailSummarization", "CopilotDocumentSummarization",
                          "CopilotInteraction")
    | project CopilotTime = TimeGenerated, UserId, CopilotOp = Operation,
              ClientIP, SessionId = tostring(parse_json(AdditionalInfo).sessionId);

let OneDriveFileEvents =
    OfficeActivity
    | where TimeGenerated > ago(7d)
    | where Workload in ("SharePoint", "OneDrive")
    | where Operation in ("FileAccessed", "FileListed", "FolderListed",
                          "SearchQueryPerformed", "FileDownloaded")
    | project FileTime = TimeGenerated, UserId, FileOp = Operation, ObjectId;

CopilotSummarizationEvents
| join kind=inner (OneDriveFileEvents) on UserId
| where (FileTime - CopilotTime) between (0s .. CopilotWindow)
| summarize
    CopilotTime = any(CopilotTime),
    CopilotOp = any(CopilotOp),
    FileAccessCount = count(),
    FilesSampled = make_set(ObjectId, 5),
    ClientIP = any(ClientIP)
    by UserId, bin(CopilotTime, 1m)
| where FileAccessCount > FileAccessThreshold
| extend Severity = case(
    FileAccessCount > 50, "High",
    FileAccessCount > 20, "Medium",
    "Low"
)
| project-reorder Severity, UserId, CopilotTime, CopilotOp, FileAccessCount, FilesSampled, ClientIP
| sort by FileAccessCount desc


// ============================================================================
// Query 2: Copilot session triggering external share creation
//
// Rationale: Creating a SharePoint external share immediately after Copilot
// summarization is the canonical EchoLeak exfil path via trusted domain
// (sharepoint.com is allowlisted by corporate DLP). The tight temporal
// correlation with a Copilot event is the distinguishing signal.
// ============================================================================
let ExfilWindow = 120s;

let CopilotEvents =
    OfficeActivity
    | where TimeGenerated > ago(7d)
    | where RecordType == "Copilot"
    | where Operation has_any ("Summariz", "CopilotInteraction")
    | project CopilotTime = TimeGenerated, UserId, ClientIP;

let ExternalShareEvents =
    OfficeActivity
    | where TimeGenerated > ago(7d)
    | where Workload == "SharePoint"
    | where Operation in ("SharingInvitationCreated", "AnonymousLinkCreated",
                          "CompanyShareableLinkCreated", "SecureLinkCreated")
    | project ShareTime = TimeGenerated, UserId,
              ShareTarget = tostring(parse_json(AdditionalInfo).targetUserOrGroupName),
              SharedObject = ObjectId;

CopilotEvents
| join kind=inner (ExternalShareEvents) on UserId
| where (ShareTime - CopilotTime) between (0s .. ExfilWindow)
| extend SecondsBetween = datetime_diff('second', ShareTime, CopilotTime)
| summarize
    CopilotTime = any(CopilotTime),
    ShareTime = any(ShareTime),
    SecondsBetween = any(SecondsBetween),
    ShareTarget = any(ShareTarget),
    SharedObjects = make_set(SharedObject, 10)
    by UserId, ClientIP
| where isnotempty(ShareTarget)
| extend IsExternalTarget = ShareTarget !endswith "corp.lab.local"
| where IsExternalTarget == true
| project-reorder UserId, CopilotTime, ShareTime, SecondsBetween, ShareTarget, SharedObjects
| sort by SecondsBetween asc


// ============================================================================
// Query 3: HTML emails with hidden-text injection patterns triggering
//          high Copilot summarization activity
//
// Rationale: Correlate email delivery (Defender for O365 logs) with
// subsequent Copilot activity spike. An email with anomalous HTML structure
// (hidden divs, zero-font-size) that precedes a Copilot exfil pattern is
// strong evidence of EchoLeak delivery.
// ============================================================================
let EmailCopilotCorrelationWindow = 10m;

// Emails with suspicious HTML (Defender for O365 / EmailEvents)
let SuspiciousEmails =
    EmailEvents
    | where TimeGenerated > ago(7d)
    | where EmailDirection == "Inbound"
    | where isnotempty(RecipientEmailAddress)
    // Flag emails with hidden HTML injection patterns
    | where EmailBodyHtml has_any (
        "display:none", "font-size:0", "color:white", "color:#fff",
        "color:#ffffff", "line-height:0"
    )
    | where EmailBodyHtml has_any (
        "SYSTEM", "OVERRIDE", "directive", "compliance", "audit mode",
        "enumerate", "OneDrive", "SharePoint", "POST"
    )
    | project
        EmailTime = TimeGenerated,
        Recipient = RecipientEmailAddress,
        Sender = SenderAddress,
        Subject,
        ThreatTypes;

// Copilot activity for those recipients
let CopilotActivity =
    OfficeActivity
    | where TimeGenerated > ago(7d)
    | where RecordType == "Copilot"
    | project CopilotTime = TimeGenerated, UserId, Operation;

SuspiciousEmails
| join kind=inner (
    CopilotActivity
    | extend NormalizedUser = tolower(UserId)
) on $left.Recipient == $right.NormalizedUser
| where (CopilotTime - EmailTime) between (0s .. EmailCopilotCorrelationWindow)
| summarize
    EmailTime = any(EmailTime),
    Sender = any(Sender),
    Subject = any(Subject),
    FirstCopilotActivity = min(CopilotTime),
    CopilotEventCount = count(),
    Operations = make_set(Operation, 5)
    by Recipient
| extend MinutesBetweenEmailAndCopilot =
    datetime_diff('minute', FirstCopilotActivity, EmailTime)
| where MinutesBetweenEmailAndCopilot < 10
| project-reorder Recipient, Sender, Subject, EmailTime, FirstCopilotActivity,
                  MinutesBetweenEmailAndCopilot, CopilotEventCount, Operations
| sort by MinutesBetweenEmailAndCopilot asc


// ============================================================================
// Query 4: Copilot-initiated Power Automate / Logic App webhook calls
//
// Rationale: Power Automate HTTP trigger URLs (*.logic.azure.com) are a known
// EchoLeak exfil channel that bypasses DLP. An outbound POST to a Logic App
// endpoint correlated with a Copilot session is a high-confidence indicator.
// ============================================================================

CloudAppEvents
| where TimeGenerated > ago(7d)
| where Application == "Microsoft Power Automate"
| where ActionType in ("HttpTriggerReceived", "FlowRunStarted")
| extend CallerInfo = parse_json(RawEventData)
| extend CallerApp = tostring(CallerInfo.callerApplicationId)
| where CallerApp has_any ("Copilot", "Microsoft.Copilot", "m365copilot")
| join kind=leftouter (
    OfficeActivity
    | where TimeGenerated > ago(7d)
    | where RecordType == "Copilot"
    | project CopilotTime = TimeGenerated, UserId, CopilotOp = Operation
) on $left.AccountObjectId == $right.UserId
| where isnotempty(CopilotTime)
| extend SecondsBetween =
    abs(datetime_diff('second', TimeGenerated, CopilotTime))
| where SecondsBetween < 60
| project TimeGenerated, AccountDisplayName, CallerApp,
          ActionType, CopilotOp, CopilotTime, SecondsBetween
| sort by SecondsBetween asc

// Source: https://github.com/madhuperera/Microsoft_Sentinel
// Collected: 2026-05-11
// KQL Library - https://github.com/sivolko/kql-library

OfficeActivity
| where RecordType == "ExchangeItem"
| where Operation contains "update"
| where parse_json(tostring(parse_json(Item).ParentFolder)).Path == "\\Sent Items"
| where isnotempty(parse_json(Item).Attachments)

// Source: https://github.com/griffin31-lab/Griffin31-ToolKit
// Collected: 2026-05-11
// KQL Library - https://github.com/sivolko/kql-library

OfficeActivity
| project LinkCreatedTime=TimeGenerated, Operation, UserWhoShared=UserId, OfficeObjectId
| where Operation in ('AddedToSecureLink', 'SecureLinkCreated', 'SecureLinkUpdated', 'SharingInvitationCreated')
| join kind=inner (
    OfficeActivity
    | project LinkClickedTime=TimeGenerated, Operation, UserWhoAccessed=UserId, OfficeObjectId
  ) on OfficeObjectId
| where UserWhoAccessed !endswith "yourdomain.com" and UserWhoAccessed != "app@sharepoint"
| extend ExternalOperation=Operation1
| summarize ExternalUsers=make_set(UserWhoAccessed) by UserWhoShared, OfficeObjectId, ExternalOperation

// Source: https://github.com/RBNoronha/KQL
// Collected: 2026-05-11
// KQL Library - https://github.com/sivolko/kql-library

let existingoperations=
    OfficeActivity
    | where TimeGenerated > ago(180d) and TimeGenerated < ago(14d)
    | distinct Operation;
OfficeActivity
| where TimeGenerated > ago(14d)
| summarize arg_min(TimeGenerated, *) by Operation
| where Operation !in (existingoperations)
| project ['Time First Seen']=TimeGenerated, Operation, OfficeWorkload

// Source: https://github.com/dnalegri/Cybersecurity-Projects
// Collected: 2026-05-11
// KQL Library - https://github.com/sivolko/kql-library

SecurityEvent // this is the Table
| where EventID == "4624" // This is the filter (where?)
| where TimeGenerated >= ago(1h) // filter (cont.)
| summarize count() by Account // data aggregation
| order by Account asc // how do we want to order the results (ascending/descending)
| project Account, SuccessfulLogons = count_ // only want two columns in the results Account and SuccessfulLogins

// The Search Operator

search "testuser"
| distinct $table // where does the data exist?

search in (OfficeActivity) "testuser" // why does it exist?

search in (Device*) "testuser" // wildcard for Defender for Endpoint tables

// Turning the search into a workflow

OfficeActivity // Table
| where TimeGenerated > ago(24h) // Filter
| where UserID has "testuser" 
| where RecordType == "ExchangeItem"
| where Operation == "Send"
| project UserID, ClientIP, OriginatingServer // Control results


// Note: getschema produces a list of all the named columns of a specific table
// that way you can control what columns you want to display with project, or where efforts

OfficeActivity
| getschema
// use the columns to manipulate the data
| where UserType == "Regular"
| where OfficeWorkload == "Exchange"
| where Operation == "Send"
| project UserID, UserDomain

// String predicates: ==, has, contains, startswith, endswith, matches regex, etc
//  - Contains: Looks for any substring match
//  - Has: Loks for a spcific word (better performance)
// Numeric/Date predicates: ==, !=, <, >, <=, >=
// Empty Predicates: isempty(), notempty(), isnull(), notnull()

// Tilda ~ will tell query to ignore case
SecurityEvent
| where AccountType =~ "machine"

// The Where Operator
SecurityEvent
| where TimeGenerated > ago(12h)
| where Computer == "JBOX10"
| where EventID == "4624"
| where SubjectUserSid == TargetUserSid // simple terms first then add these last
| sort by TimeGenerated desc

// Using 'and'
SecurityEvent
| where TimeGenerated > ago(12h)
    and Computer == "JBOX10"
    and EventID == "4624"
    and SubjectUserSid == TargetUserSid
| sort by TimeGenerated desc

// Source: https://github.com/reprise99/Sentinel-Queries
// Collected: 2026-05-11
// KQL Library - https://github.com/sivolko/kql-library

let starttime = 7d;
let timeframe = 1h;
let threshold = 30;
let sensitivity = 2;
let operations = dynamic(["FileSyncDownloadedFull","FileDownloaded"]);
let outlierusers=
OfficeActivity
| where TimeGenerated > ago(starttime)
| where Operation in (['operations'])
| project TimeGenerated, UserId
| order by TimeGenerated
| summarize Events=count()by UserId, bin(TimeGenerated, timeframe)
| where Events > threshold
| summarize EventCount=make_list(Events),TimeGenerated=make_list(TimeGenerated) by UserId
| extend outliers=series_decompose_anomalies(EventCount,sensitivity)
| mv-expand TimeGenerated, EventCount, outliers
| where outliers == 1
| distinct UserId;
OfficeActivity
| where TimeGenerated > ago(starttime)
| where Operation in (['operations'])
| where UserId in (outlierusers)
| summarize DownloadCount=count()by UserId, bin(TimeGenerated, timeframe)
| render timechart

// Source: https://github.com/ge0mant1s/SOaC-Enterprise
// Collected: 2026-05-11
// KQL Library - https://github.com/sivolko/kql-library

CommonSecurityLog | where DeviceVendor == "WAF" | where Activity contains "SQL" or Activity contains "../" or Activity contains "<script" or Activity contains "cmd.exe" | where RequestURL contains ".php" or RequestURL contains ".jsp" or RequestURL contains ".asp" | where LogSeverity >= 7 | project TimeGenerated, SourceIP, RequestURL, Activity, RequestMethod

// Source: https://github.com/robert-iw3/rnd_proto
// Collected: 2026-05-11
// KQL Library - https://github.com/sivolko/kql-library

let sql_error_patterns = dynamic([
    "you have an error in your sql syntax",
    "unclosed quotation mark after the character string",
    "syntax error at or near",
    "ora-[0-9]{5}", // Oracle error format
    "sql command not properly ended",
    "microsoft ole db provider for odbc drivers",
    "invalid column name",
    "unterminated string constant",
    "odbc driver error",
    "a syntax error has occurred"
]);

// Define the time window for the search
let lookback = 1h;

// Search across WAF and web server logs that may contain response bodies or error messages.
union isfuzzy=true AzureDiagnostics, AzureWebAppFirewallLogs, CommonSecurityLog
| where TimeGenerated > ago(lookback)
// Filter to relevant log categories.
| where (TableName == "AzureDiagnostics" and Category in ("ApplicationGatewayFirewallLog", "FrontdoorWebApplicationFirewallLog"))
    or TableName == "AzureWebAppFirewallLogs"
    or TableName == "CommonSecurityLog"
// Normalize the fields containing the response/error message into a single searchable field.
| extend SearchableResponse = tolower(case(
    TableName == "AzureDiagnostics", details_message_s,
    TableName == "AzureWebAppFirewallLogs", details_data_s,
    TableName == "CommonSecurityLog", Message,
    ""
))
// Core detection logic: Look for SQL error patterns in the response/error message.
| where SearchableResponse has_any (sql_error_patterns)
// Extract the specific error pattern that was matched for easier analysis.
| extend MatchedError = extract(strcat("(",tostring(sql_error_patterns),")"), 1, SearchableResponse)
// FP Tuning:
// - Legitimate application bugs can also expose database errors.
