CloudAppEvents
| where TimeGenerated > ago(30d)
| where ActionType has_any ("AgentAccessGranted", "CopilotAgentUserAccess", "AgentUserAdded")
| extend AgentName = tostring(RawEventData.AgentName)
| extend GrantedToUser = tostring(RawEventData.GrantedTo)
| join kind=leftouter (IdentityInfo | summarize arg_max(TimeGenerated,*) by AccountUpn | project AccountUpn, Department, JobTitle, City) on $left.AccountId == $right.AccountUpn
| project TimeGenerated, AccountDisplayName, Department, AgentName, GrantedToUser, IPAddress
| order by TimeGenerated desc

// Title: Unusual User Agent from Registered Device Bypassing Conditional Access
// Author: Jose Sebastian Canos
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
let lookback = 14d;
let BaselineWindow = 30d;
let KnownUserAgents = SigninLogs
    | where TimeGenerated between (ago(BaselineWindow) .. ago(lookback))
    | where isnotempty(tostring(DeviceDetail.deviceId))
    | summarize BaselineUAs = make_set(tostring(UserAgent), 20) by UserPrincipalName;
SigninLogs
| where TimeGenerated > ago(lookback)
| where isnotempty(tostring(DeviceDetail.deviceId))
| where ConditionalAccessStatus != "failure"
| extend DeviceTrust = tostring(DeviceDetail.trustType)
| join kind=leftouter KnownUserAgents on UserPrincipalName
| where not(set_has_element(BaselineUAs, tostring(UserAgent)))
| summarize UnknownUAs = make_set(tostring(UserAgent),5), Count = count() by UserPrincipalName, DeviceTrust
| where Count >= 3
| order by Count desc

// Title: Defender RedSun Named Pipe Detection Correlated to AV
// Author: Jay Kerai
// Source: https://www.kqlsearch.com
// MITRE: T1055 - Process Injection
// KQL Library - https://github.com/sivolko/kql-hunter
let NamedPipeEvents = DeviceEvents
| where Timestamp > ago(7d)
| where ActionType == "NamedPipeEvent"
| where AdditionalFields has_any ("redsun", "RedSun", "\\pipe\\")
| project DeviceId, DeviceName, PipeTime = Timestamp, PipeName = tostring(parse_json(AdditionalFields).PipeName);
NamedPipeEvents
| join kind=inner (
    DeviceProcessEvents
    | where Timestamp > ago(7d)
    | where InitiatingProcessFileName has_any ("MsMpEng", "antivirus", "defender")
    | project DeviceId, AVTime = Timestamp, AVProcess = FileName, AVCmd = ProcessCommandLine
) on DeviceId
| where AVTime between (PipeTime - 5m .. PipeTime + 5m)
| project DeviceName, PipeTime, PipeName, AVTime, AVProcess, AVCmd
| order by PipeTime desc

// Title: Defender RedSun TieringEngineService in AppData
// Author: Jay Kerai
// Source: https://www.kqlsearch.com
// MITRE: T1036 - Masquerading
// KQL Library - https://github.com/sivolko/kql-hunter
DeviceFileEvents
| where Timestamp > ago(7d)
| where FileName has_any ("TieringEngineService", "tieringengineservice")
| where FolderPath has_any ("AppData", "\\appdata\\")
| where ActionType in ("FileCreated", "FileModified")
| project Timestamp, DeviceName, FolderPath, FileName, SHA256, InitiatingProcessFileName, InitiatingProcessCommandLine, InitiatingProcessAccountName
| order by Timestamp desc

// Title: Suspicious Device Code Authentication
// Author: Jose Sebastian Canos
// Source: https://www.kqlsearch.com
// MITRE: T1566.002 - Spearphishing Link
// KQL Library - https://github.com/sivolko/kql-hunter
let lookback = 7d;
let DeviceCodeSignins = SigninLogs
| where TimeGenerated > ago(lookback)
| where AuthenticationProtocol == "deviceCode" or ClientAppUsed == "Device Login"
| where ResultType == "0"
| project UPN = UserPrincipalName, SignInTime = TimeGenerated, IPAddress, Location, DeviceId = tostring(DeviceDetail.deviceId);
DeviceCodeSignins
| where isempty(DeviceId)
| summarize Count = count(), IPs = make_set(IPAddress, 10), Locations = make_set(Location, 10) by UPN, bin(SignInTime, 1h)
| where Count >= 2
| order by Count desc

// Title: Users Authenticating with the MFA Companion App
// Author: Nathan Hutchinson
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
SigninLogs
| where TimeGenerated > ago(30d)
| where ResultType == "0"
| where isnotempty(AuthenticationDetails)
| mv-expand AuthStep = parse_json(AuthenticationDetails)
| extend MFAMethod = tostring(AuthStep.authenticationMethod)
| where MFAMethod has_any ("Companion", "companion app", "MicrosoftAuthenticator")
| summarize SignInCount = count(), LastSeen = max(TimeGenerated) by UserPrincipalName, MFAMethod
| order by SignInCount desc

// Title: Detect TLS Validation Bypass via PowerShell
// Author: Sergio Albea
// Source: https://www.kqlsearch.com
// MITRE: T1562 - Impair Defenses
// KQL Library - https://github.com/sivolko/kql-hunter
DeviceProcessEvents
| where Timestamp > ago(30d)
| where FileName in~ ("powershell.exe", "pwsh.exe")
| where ProcessCommandLine has_any (
    "ServerCertificateValidationCallback",
    "[System.Net.ServicePointManager]::ServerCertificateValidationCallback",
    "SkipCertificateCheck",
    "[System.Net.ServicePointManager]::SecurityProtocol",
    "CertificatePolicy",
    "TrustAllCertsPolicy"
)
| project Timestamp, DeviceName, AccountName, ProcessCommandLine, InitiatingProcessFileName, InitiatingProcessCommandLine
| order by Timestamp desc

// Title: Audit Claude AI Behavior on Endpoints
// Author: Benjamin Zulliger
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
DeviceProcessEvents
| where Timestamp > ago(30d)
| where ProcessCommandLine has_any ("claude", "anthropic", "claude.exe", "claude-code")
    or FileName has_any ("claude", "anthropic")
| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName
| union (
    DeviceFileEvents
    | where Timestamp > ago(30d)
    | where FolderPath has_any ("claude", "anthropic", ".claude")
    | project Timestamp, DeviceName, AccountName = InitiatingProcessAccountName, FileName, FolderPath, ActionType
)
| order by Timestamp desc

// Title: Git Force Push Detection
// Author: Ali Hussein
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
DeviceProcessEvents
| where Timestamp > ago(30d)
| where ProcessCommandLine has "git push"
| where ProcessCommandLine has_any ("-f", "--force", "--force-with-lease", "-uf")
| project Timestamp, DeviceName, AccountName, ProcessCommandLine, InitiatingProcessFileName, InitiatingProcessCommandLine
| extend Repo = extract(@"origin\s+(\S+)", 1, ProcessCommandLine)
| order by Timestamp desc

// Title: Git Commit --amend --no-verify
// Author: Ali Hussein
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
DeviceProcessEvents
| where Timestamp > ago(30d)
| where ProcessCommandLine has "git commit"
| where ProcessCommandLine has "--amend"
| where ProcessCommandLine has "--no-verify"
| project Timestamp, DeviceName, AccountName, ProcessCommandLine, InitiatingProcessFileName
| order by Timestamp desc

// Title: Batch Git Abuse Detection
// Author: Ali Hussein
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
DeviceProcessEvents
| where Timestamp > ago(30d)
| where InitiatingProcessFileName in~ ("cmd.exe", "powershell.exe")
| where ProcessCommandLine has "git"
| where ProcessCommandLine has_any ("--amend", "--force", "config --local", "--no-verify", "reset --hard")
| summarize AbuseCount = count(), Commands = make_set(ProcessCommandLine, 10) by DeviceId, DeviceName, AccountName, bin(Timestamp, 10m)
| where AbuseCount >= 2
| order by AbuseCount desc

// Title: Defense Evasion Git Time Change
// Author: Ali Hussein
// Source: https://www.kqlsearch.com
// MITRE: T1070 - Indicator Removal
// KQL Library - https://github.com/sivolko/kql-hunter
let GitCommits = DeviceProcessEvents
| where Timestamp > ago(30d)
| where ProcessCommandLine has "git commit"
| project DeviceId, CommitTime = Timestamp;
let TimeChanges = DeviceProcessEvents
| where Timestamp > ago(30d)
| where FileName in~ ("cmd.exe", "powershell.exe")
| where ProcessCommandLine has_any ("date ", "time ", "Set-Date", "w32tm")
| project DeviceId, DeviceName, AccountName, ChangeTime = Timestamp, ChangeCmd = ProcessCommandLine;
TimeChanges
| join kind=inner GitCommits on DeviceId
| where CommitTime between (ChangeTime - 5m .. ChangeTime + 5m)
| project DeviceName, AccountName, ChangeTime, ChangeCmd, CommitTime
| order by ChangeTime desc

// Title: Defense Evasion Git Config Masquerade
// Author: Ali Hussein
// Source: https://www.kqlsearch.com
// MITRE: T1036 - Masquerading
// KQL Library - https://github.com/sivolko/kql-hunter
DeviceProcessEvents
| where Timestamp > ago(30d)
| where ProcessCommandLine has "git config"
| where ProcessCommandLine has_any ("user.name", "user.email")
| extend TargetIdentity = extract(@"(user\.(?:name|email))\s+(.+)", 2, ProcessCommandLine)
| project Timestamp, DeviceName, AccountName, ProcessCommandLine, TargetIdentity, InitiatingProcessFileName
| order by Timestamp desc

// Title: Correlation Git and VS Code Task Abuse
// Author: Ali Hussein
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
DeviceProcessEvents
| where Timestamp > ago(30d)
| where InitiatingProcessFileName in~ ("code.exe", "code", "Code - OSS")
| where ProcessCommandLine has "git"
| where ProcessCommandLine has_any ("--amend", "--force", "config --local", "--no-verify", "reset", "rebase")
| project Timestamp, DeviceName, AccountName, ProcessCommandLine, InitiatingProcessFileName, InitiatingProcessCommandLine
| order by Timestamp desc

// Title: IFEO Unauthorized Debugger Registration
// Author: Benjamin Zulliger
// Source: https://www.kqlsearch.com
// MITRE: T1546.012 - Event Triggered Execution: Image File Execution Options Injection
// KQL Library - https://github.com/sivolko/kql-hunter
DeviceRegistryEvents
| where Timestamp > ago(30d)
| where RegistryKey has @"SOFTWARE\Microsoft\Windows NT\CurrentVersion\Image File Execution Options"
| where RegistryValueName in~ ("Debugger", "GlobalFlag")
| where ActionType in ("RegistryValueSet", "RegistryKeyCreated")
| extend DebuggerValue = tostring(RegistryValueData)
| where isnotempty(DebuggerValue)
| where not(DebuggerValue has_any ("vsjitdebugger", "ntsd", "windbg"))
| project Timestamp, DeviceName, AccountName = InitiatingProcessAccountName, RegistryKey, RegistryValueName, DebuggerValue, InitiatingProcessFileName, InitiatingProcessCommandLine
| order by Timestamp desc

// Title: macOS Suspicious Shell or Process from Browser
// Author: Benjamin Zulliger
// Source: https://www.kqlsearch.com
// MITRE: T1203 - Exploitation for Client Execution
// KQL Library - https://github.com/sivolko/kql-hunter
DeviceProcessEvents
| where Timestamp > ago(30d)
| where OSPlatform == "macOS"
| where InitiatingProcessFileName in~ ("Google Chrome", "Safari", "Firefox", "Microsoft Edge", "Chromium")
| where FileName in~ ("bash", "sh", "zsh", "python", "python3", "perl", "ruby", "osascript", "curl", "wget")
| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName, InitiatingProcessCommandLine
| order by Timestamp desc

// Title: Node C2 Polinder Detection
// Author: Ali Hussein
// Source: https://www.kqlsearch.com
// MITRE: T1071 - Application Layer Protocol
// KQL Library - https://github.com/sivolko/kql-hunter
DeviceNetworkEvents
| where Timestamp > ago(7d)
| where InitiatingProcessFileName in~ ("node.exe", "node", "nodejs")
| where not(ipv4_is_private(RemoteIP))
| where RemotePort !in (80, 443, 8080, 8443)
| extend ProcessDir = extract(@"(.+)\\[^\\]+$", 1, InitiatingProcessFolderPath)
| where ProcessDir has_any ("AppData", "Temp", "Downloads", "Users")
| project Timestamp, DeviceName, RemoteIP, RemotePort, RemoteUrl, InitiatingProcessFileName, InitiatingProcessCommandLine, InitiatingProcessFolderPath
| order by Timestamp desc

// Title: Microsoft Defender Cloud App Discovery to Log Analytics
// Author: Benjamin Zulliger
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
// Query the custom table populated by Cloud App Discovery export
CloudAppRiskCatalog_CL
| where TimeGenerated > ago(30d)
| extend AppName = tostring(parse_json(RawData).AppName)
| extend RiskScore = toint(parse_json(RawData).RiskScore)
| extend Category = tostring(parse_json(RawData).Category)
| extend Users = toint(parse_json(RawData).Users)
| extend Transactions = toint(parse_json(RawData).Transactions)
| where RiskScore >= 5
| summarize AppCount = count(), MaxRisk = max(RiskScore), TotalUsers = sum(Users) by Category
| order by TotalUsers desc
